sql:
SELECT COUNT(passenger_id)
FROM passenger_embarkation
WHERE embarkation_point_id = 3 AND passenger_id BETWEEN 25 AND 35;

SELECT pv.passenger_id, v.voyage_name
FROM passenger_voyage_association pv
INNER JOIN voyages v ON pv.voyage_id = v.voyage_id;

SELECT voyage_name
FROM voyages
WHERE number_of_passengers > 1000;

SELECT ship_name
FROM ships
WHERE capacity > 2000;

SELECT * 
FROM voyages 
WHERE voyage_id > 100;

SELECT * 
FROM versions 
WHERE version_id = (
  SELECT MAX(version_id) 
  FROM versions
);

SELECT source_name, last_updated, provider
FROM data_sources
ORDER BY last_updated DESC;

external_knowledge:
'New millennium' refers to the start of the year 2000;
'Major ocean liner journeys' are voyages undertaken by ships classified as 'Ocean Liner';
'Significant historical events' are captured in the historical_events table linked to the voyages through the historical_event_id;
'Carried more than a thousand travelers' indicates voyages with over 1000 passengers.
